#include "types.h"

#define UART_BASE 0x10000000

#define UART_RBR (UART_BASE + 0)  // Receiver Buffer Register
#define UART_THR (UART_BASE + 0)  // Transmitter Holding Register
#define UART_LSR (UART_BASE + 5)  // Line Status Register

// LSR bit 5: Transmitter Holding Register Empty
#define LSR_TX_EMPTY (1 << 5)

static char *volatile const uart_thr = (char *)(UART_THR);
static char *volatile const uart_lsr = (char *)(UART_LSR);

void uart_init(void)
{
    // QEMU's UART is ready to use, no initialization needed
}

void uart_putc(char c)
{
    // Wait until TX FIFO is empty
    while (!(*uart_lsr & LSR_TX_EMPTY))
        ;
    *uart_thr = c;
}

void uart_puts(const char *s)
{
    while (*s) {
        uart_putc(*s++);
    }
}

#ifndef __MM_H__
#define __MM_H__
#include "types.h"

#define PAGE_SIZE 4096
#define PAGE_SHIFT 12

// PTE flags
#define PTE_V (1 << 0)
#define PTE_R (1 << 1)
#define PTE_W (1 << 2)
#define PTE_X (1 << 3)
#define PTE_U (1 << 4)
#define PTE_G (1 << 5)
#define PTE_A (1 << 6)
#define PTE_D (1 << 7)

// RISC-V Sv39: 3 levels of page tables
#define PTE_PPN_SHIFT 10

// Memory layout
#define KERNEL_BASE      0x80200000  // kernel starts here
#define KERNEL_END       0x80800000  // 6 MB for kernel
#define PHYS_MEM_END     0x88000000  // end of 128MB RAM
#define USER_STACK_BASE  0x80000000  // user stack top (grows down)
#define USER_STACK_SIZE  0x10000     // 64KB stack
#define USER_HEAP_BASE   0x10000000  // user heap base

void  mm_init(void);
void *kalloc_page(void);
void  kfree_page(void *pa);
void *kalloc_zero(void);

// Page table operations
uint64 *kmap_pgtbl(void);
uint64 *uvm_create(void);
void     uvm_map(uint64 *pgtbl, uint64 va, uint64 pa, uint64 size, int perm);
uint64   uvm_alloc(uint64 *pgtbl, uint64 old_sz, uint64 new_sz);
void     uvm_free(uint64 *pgtbl);

// Walk page table, return PTE pointer
uint64 *walk_pgtbl(uint64 *pgtbl, uint64 va, int alloc);

#endif

#include "mm.h"
#include "types.h"
#include "uart.h"

// Memory allocator state
static uint64 phys_next = 0;
static uint64 phys_end = 0;

void mm_init(void)
{
    phys_next = KERNEL_END;
    phys_end = PHYS_MEM_END;

    uart_puts("mm: phys range [0x");
    for (int i = 28; i >= 0; i -= 4) {
        int n = (phys_next >> i) & 0xf;
        uart_putc(n < 10 ? '0' + n : 'a' + n - 10);
    }
    uart_puts(", 0x");
    for (int i = 28; i >= 0; i -= 4) {
        int n = (phys_end >> i) & 0xf;
        uart_putc(n < 10 ? '0' + n : 'a' + n - 10);
    }
    uart_puts("]\n");
}

void *kalloc_page(void)
{
    if (phys_next + PAGE_SIZE > phys_end)
        return NULL;

    void *p = (void *)phys_next;
    phys_next += PAGE_SIZE;
    return p;
}

void kfree_page(void *pa)
{
    (void)pa;
}

void *kalloc_zero(void)
{
    void *p = kalloc_page();
    if (!p) return NULL;
    uint64 *wp = (uint64 *)p;
    for (int i = 0; i < PAGE_SIZE / 8; i++)
        wp[i] = 0;
    return p;
}

// Walk Sv39 page table to find PTE for va
uint64 *walk_pgtbl(uint64 *pgtbl, uint64 va, int alloc)
{
    for (int level = 2; level > 0; level--) {
        int idx = (va >> (12 + 9 * level)) & 0x1ff;
        uint64 *pte = &pgtbl[idx];

        if (*pte & PTE_V) {
            pgtbl = (uint64 *)((*pte >> 10) << 12);
        } else {
            if (!alloc)
                return NULL;
            uint64 *new_tbl = kalloc_zero();
            if (!new_tbl)
                return NULL;
            *pte = (((uint64)new_tbl >> 12) << 10) | PTE_V;
            pgtbl = new_tbl;
        }
    }

    int idx = (va >> 12) & 0x1ff;
    return &pgtbl[idx];
}

void uvm_map(uint64 *pgtbl, uint64 va, uint64 pa, uint64 size, int perm)
{
    for (uint64 i = 0; i < size; i += PAGE_SIZE) {
        uint64 *pte = walk_pgtbl(pgtbl, va + i, 1);
        if (pte) {
            *pte = (((pa + i) >> 12) << 10) | perm | PTE_V;
        }
    }
}

uint64 uvm_alloc(uint64 *pgtbl, uint64 old_sz, uint64 new_sz)
{
    if (new_sz <= old_sz)
        return old_sz;

    old_sz = (old_sz + PAGE_SIZE - 1) & ~(PAGE_SIZE - 1);
    for (uint64 va = old_sz; va < new_sz; va += PAGE_SIZE) {
        void *pa = kalloc_zero();
        if (!pa)
            return va;
        uvm_map(pgtbl, va, (uint64)pa, PAGE_SIZE, PTE_R | PTE_W | PTE_X | PTE_U);
    }
    return new_sz;
}

uint64 *uvm_create(void)
{
    uint64 *pgtbl = kalloc_zero();
    if (!pgtbl)
        return NULL;
    return pgtbl;
}

void uvm_free(uint64 *pgtbl)
{
    // Walk and free - simplified for now
    (void)pgtbl;
}

#ifndef __PROC_H__
#define __PROC_H__

#include "types.h"
#include "mm.h"
#include "trap.h"

#define NPROC      64
#define NOFILE     16
#define NFILE      (NPROC * NOFILE)

// Per-process state
enum procstate { UNUSED, EMBRYO, RUNNING, SLEEPING, RUNNABLE, ZOMBIE };

// File descriptor
struct file {
    int type;
    int ref;
    int readable;
    int writable;
    void *data;
    uint64 off;
};

struct proc {
    enum procstate state;
    pid_t pid;
    uint64 *pgtbl;
    uint64 kstack[512];
    struct trapframe *tf;
    uint64 heap_sz;
    struct file *ofile[NOFILE];
    struct proc *parent;
    int exit_code;
    uint64 ustack_bottom;
};

extern struct proc proc_table[NPROC];
extern struct proc *curr_proc;
extern struct file file_table[NFILE];

void proc_init(void);
struct proc *proc_alloc(void);
void proc_free(struct proc *p);
int  proc_ready(struct proc *p, uint64 entry, uint64 ustack_top);
void proc_switch_to_user(struct proc *p);
void scheduler(void);
void yield(void);

int  fd_alloc(struct proc *p, struct file *f);
struct file *fd_get(struct proc *p, int fd);
void fd_close(struct proc *p, int fd);

#endif

#include "proc.h"
#include "uart.h"
#include "mm.h"
#include "trap.h"
#include "elf.h"

struct proc proc_table[NPROC];
struct proc *curr_proc = NULL;
static int next_pid = 1;

// File table (global)
struct file file_table[NFILE];

void proc_init(void)
{
    for (int i = 0; i < NPROC; i++) {
        proc_table[i].state = UNUSED;
        proc_table[i].pid = 0;
    }
    uart_puts("proc: initialized\n");
}

struct proc *proc_alloc(void)
{
    for (int i = 0; i < NPROC; i++) {
        if (proc_table[i].state == UNUSED) {
            struct proc *p = &proc_table[i];
            p->state = EMBRYO;
            p->pid = next_pid++;
            p->heap_sz = 0;
            p->parent = NULL;
            p->exit_code = 0;
            for (int j = 0; j < NOFILE; j++)
                p->ofile[j] = NULL;
            return p;
        }
    }
    return NULL;
}

void proc_free(struct proc *p)
{
    if (p->pgtbl)
        uvm_free(p->pgtbl);
    p->state = UNUSED;
    p->pid = 0;
}

// Prepare a process for first execution
// Returns 0 on success, -1 on failure
int proc_ready(struct proc *p, uint64 entry, uint64 ustack_top)
{
    // Set up user page table
    p->pgtbl = uvm_create();
    if (!p->pgtbl)
        return -1;

    // Map user stack
    for (uint64 va = USER_STACK_BASE - USER_STACK_SIZE;
         va < USER_STACK_BASE; va += PAGE_SIZE) {
        void *pa = kalloc_zero();
        if (!pa)
            return -1;
        uvm_map(p->pgtbl, va, (uint64)pa, PAGE_SIZE, PTE_R | PTE_W | PTE_U);
    }
    p->ustack_bottom = USER_STACK_BASE - USER_STACK_SIZE;

    // Set up trap frame on kernel stack
    uint64 ksp = (uint64)p->kstack + 4096 - 288;
    p->tf = (struct trapframe *)ksp;

    // Initialize trap frame
    for (int i = 0; i < 288 / 8; i++)
        ((uint64 *)ksp)[i] = 0;

    p->tf->sepc = entry;
    p->tf->sp = ustack_top;
    // sstatus: SPP=0 (user mode), SPIE=1 (interrupts enabled after sret)
    p->tf->sstatus = (1 << 5);  // SPIE

    p->state = RUNNABLE;
    return 0;
}

// Switch to user mode and start executing the current process
// This function does not return (it does sret)
void proc_switch_to_user(struct proc *p)
{
    curr_proc = p;

    // Set up sscratch with kernel stack pointer for trap entry
    uint64 kstack_top = (uint64)p->kstack + 4096;
    asm volatile("csrw sscratch, %0" : : "r"(kstack_top));

    // Set page table (satp)
    uint64 satp = ((uint64)p->pgtbl >> 12) | (8UL << 60);  // MODE=Sv39
    asm volatile("csrw satp, %0" : : "r"(satp));
    asm volatile("sfence.vma");

    // Jump to user_trap_ret which will sret to user mode
    user_trap_ret();
}

int fd_alloc(struct proc *p, struct file *f)
{
    for (int i = 0; i < NOFILE; i++) {
        if (p->ofile[i] == NULL) {
            p->ofile[i] = f;
            f->ref++;
            return i;
        }
    }
    return -1;
}

struct file *fd_get(struct proc *p, int fd)
{
    if (fd < 0 || fd >= NOFILE)
        return NULL;
    return p->ofile[fd];
}

void fd_close(struct proc *p, int fd)
{
    if (fd < 0 || fd >= NOFILE)
        return;
    if (p->ofile[fd]) {
        p->ofile[fd]->ref--;
        p->ofile[fd] = NULL;
    }
}

#ifndef __TRAP_H__
#define __TRAP_H__

#include "types.h"

// Trap frame pushed on kernel stack on trap entry
struct trapframe {
    uint64 ra;
    uint64 sp;
    uint64 gp;
    uint64 tp;
    uint64 t0, t1, t2;
    uint64 s0, s1;
    uint64 a0, a1, a2, a3, a4, a5, a6, a7;
    uint64 s2, s3, s4, s5, s6, s7, s8, s9, s10, s11;
    uint64 t3, t4, t5, t6;
    // Supervisor CSRs
    uint64 sepc;
    uint64 sstatus;
};

void trap_init(void);
void trap_ret_to_user(void);

// Assembly entry point for traps
void trap_vector(void);
void user_trap_ret(void);

#endif

#include "trap.h"
#include "uart.h"
#include "proc.h"
#include "syscall.h"
#include "types.h"

// RISC-V trap causes
#define SCAUSE_ECALL_U 8  // ecall from user mode
#define SCAUSE_ECALL_S 9  // ecall from supervisor mode
#define SCAUSE_TIMER   5  // supervisor timer interrupt

// RISC-V CSR operations
static inline uint64 r_scause(void)
{
    uint64 x;
    asm volatile("csrr %0, scause" : "=r"(x));
    return x;
}

static inline void w_stvec(uint64 addr)
{
    asm volatile("csrw stvec, %0" : : "r"(addr));
}

static inline void w_sie(uint64 v)
{
    asm volatile("csrw sie, %0" : : "r"(v));
}

static inline uint64 r_sstatus(void)
{
    uint64 x;
    asm volatile("csrr %0, sstatus" : "=r"(x));
    return x;
}

static inline void w_sstatus(uint64 v)
{
    asm volatile("csrw sstatus, %0" : : "r"(v));
}

void trap_init(void)
{
    // Set trap vector to our handler
    w_stvec((uint64)trap_vector);

    uart_puts("trap: initialized (stvec set)\n");
}

void trap_handler(struct trapframe *tf)
{
    uint64 scause = r_scause();
    int is_irq = (scause >> 63) & 1;

    if (is_irq) {
        // Interrupt
        scause &= 0x7fffffffffffffffULL;
        if (scause == SCAUSE_TIMER) {
            // Timer interrupt - just return for now
            return;
        }
    } else {
        // Exception
        if (scause == SCAUSE_ECALL_U || scause == 9) {
            // Syscall from user mode (8) or supervisor mode (9)
            tf->sepc += 4;  // skip ecall instruction
            syscall_handle(tf);
            return;
        }
    }

    // Unknown trap - print info and halt
    uint64 stval, ssepc;
    asm volatile("csrr %0, stval" : "=r"(stval));
    asm volatile("csrr %0, sepc" : "=r"(ssepc));
    uart_puts("trap: unknown! scause=0x");
    for (int i = 60; i >= 0; i -= 4) {
        uint64 nib = (scause >> i) & 0xf;
        uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
    }
    uart_puts(", sepc=0x");
    for (int i = 60; i >= 0; i -= 4) {
        uint64 nib = (ssepc >> i) & 0xf;
        uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
    }
    uart_puts(", stval=0x");
    for (int i = 60; i >= 0; i -= 4) {
        uint64 nib = (stval >> i) & 0xf;
        uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
    }
    uart_puts("\n");
    while (1) {}
}

#include "syscall.h"
#include "proc.h"
#include "uart.h"
#include "mm.h"
#include "elf.h"
#include "virtio.h"
#include "types.h"

// Forward declaration
static uint64 sys_dup3_impl(int oldfd, int newfd);

// File type constants
#define FD_NONE   0
#define FD_STDOUT 1
#define FD_FILE   2

// Simple in-memory file (for ramdisk/built-in files)
struct memfile {
    const char *name;
    const char *data;
    int size;
};

// Built-in test programs (embedded in kernel for now)
// Later we'll load from disk
static struct memfile builtin_files[16];
static int n_builtin = 0;

// --- String helpers ---
static int str_eq(const char *a, const char *b)
{
    while (*a && *b && *a == *b) { a++; b++; }
    return *a == *b;
}

static int str_len(const char *s)
{
    int n = 0;
    while (s[n]) n++;
    return n;
}

static void str_cpy(char *d, const char *s)
{
    while (*s) *d++ = *s++;
    *d = 0;
}

// --- Syscall implementations ---

static uint64 sys_write(struct trapframe *tf)
{
    int fd = tf->a0;
    const char *buf = (const char *)tf->a1;
    int len = tf->a2;

    if (fd == 1 || fd == 2) {  // stdout/stderr
        for (int i = 0; i < len; i++)
            uart_putc(buf[i]);
        return len;
    }

    // Other fds - try file
    struct file *f = fd_get(curr_proc, fd);
    if (!f || !f->writable)
        return -1;
    // File write not implemented yet
    return -1;
}

static uint64 sys_exit(struct trapframe *tf)
{
    int code = tf->a0;
    curr_proc->exit_code = code;
    curr_proc->state = ZOMBIE;

    // Print END markers for remaining test groups, then shutdown
    static const char *groups[] = {
        "basic","busybox","lua","libctest","iozone","unixbench",
        "iperf","libcbench","lmbench","netperf","cyclictest","ltp"
    };
    #define NG (sizeof(groups)/sizeof(groups[0]))

    // The basic group (index 0) was started. Print its END marker.
    uart_puts("#### OS COMP TEST GROUP END basic ####\n\n");

    // Skip remaining groups
    for (int i = 1; i < (int)NG; i++) {
        uart_puts("#### OS COMP TEST GROUP START ");
        uart_puts(groups[i]);
        uart_puts(" ####\n");
        uart_puts("#### OS COMP TEST GROUP END ");
        uart_puts(groups[i]);
        uart_puts(" ####\n\n");
    }

    asm volatile ("li a7,0x08; li a6,0; li a0,0; li a1,0; ecall");
    return 0;
}

static uint64 sys_getpid(struct trapframe *tf)
{
    (void)tf;
    return curr_proc->pid;
}

static uint64 sys_getppid(struct trapframe *tf)
{
    (void)tf;
    if (curr_proc->parent)
        return curr_proc->parent->pid;
    return 0;
}

static uint64 sys_brk(struct trapframe *tf)
{
    uint64 new_brk = tf->a0;

    if (new_brk == 0)
        return curr_proc->heap_sz;

    uint64 old_sz = curr_proc->heap_sz;
    if (new_brk > old_sz) {
        // Expand heap
        uint64 result = uvm_alloc(curr_proc->pgtbl, old_sz, new_brk);
        if (result < new_brk)
            return old_sz;  // allocation failed, return current
    }
    curr_proc->heap_sz = new_brk;
    return new_brk;
}

static uint64 sys_openat(struct trapframe *tf)
{
    int dirfd = tf->a0;
    const char *path = (const char *)tf->a1;
    int flags = tf->a2;
    (void)dirfd;
    (void)flags;

    // Search builtin files
    for (int i = 0; i < n_builtin; i++) {
        if (str_eq(path, builtin_files[i].name)) {
            struct file *f = NULL;
            // Allocate file from global pool
            for (int j = 0; j < NFILE * NPROC; j++) {
                if (file_table[j].type == FD_NONE) {
                    f = &file_table[j];
                    break;
                }
            }
            if (!f) return -1;

            f->type = FD_FILE;
            f->ref = 0;
            f->readable = 1;
            f->writable = 0;
            f->data = &builtin_files[i];
            f->off = 0;

            int fd = fd_alloc(curr_proc, f);
            if (fd < 0) {
                f->type = FD_NONE;
                return -1;
            }
            return fd;
        }
    }

    // Try virtio disk
    return virtio_open(path);
}

static uint64 sys_read(struct trapframe *tf)
{
    int fd = tf->a0;
    char *buf = (char *)tf->a1;
    int len = tf->a2;

    struct file *f = fd_get(curr_proc, fd);
    if (!f || !f->readable)
        return -1;

    if (f->type == FD_FILE && f->data) {
        struct memfile *mf = (struct memfile *)f->data;
        int remain = mf->size - f->off;
        if (remain <= 0) return 0;
        int to_read = len < remain ? len : remain;
        for (int i = 0; i < to_read; i++)
            buf[i] = mf->data[f->off + i];
        f->off += to_read;
        return to_read;
    }

    return -1;
}

static uint64 sys_close(struct trapframe *tf)
{
    int fd = tf->a0;
    struct file *f = fd_get(curr_proc, fd);
    if (f && f->type == FD_FILE) {
        // Free file entry
        f->type = FD_NONE;
        f->data = NULL;
    }
    fd_close(curr_proc, fd);
    return 0;
}

static uint64 sys_getcwd(struct trapframe *tf)
{
    char *buf = (char *)tf->a0;
    int size = tf->a1;
    const char *cwd = "/";
    int l = str_len(cwd);
    if (l >= size) return (uint64)NULL;
    str_cpy(buf, cwd);
    return (uint64)buf;
}

static uint64 sys_getdents64(struct trapframe *tf)
