static uint64 sys_uname(struct trapframe *tf)
{
    char *buf = (char *)tf->a0;
    // struct utsname layout (6 * 65 bytes)
    const char *names[] = {
        "OSMatch",   // sysname
        "osmatch",   // nodename
        "1.0.0",     // release
        "1.0",       // version
        "riscv64",   // machine
        ""           // domainname
    };
    char *p = buf;
    for (int i = 0; i < 6; i++) {
        str_cpy(p, names[i]);
        p += 65;
    }
    return 0;
}

