static uint64 sys_mmap(struct trapframe *tf)
{
    uint64 addr = tf->a0;
    uint64 length = tf->a1;
    int prot = tf->a2;
    int flags = tf->a3;
    (void)flags;

    if (addr == 0) {
        // Allocate from top of heap downward
        // For simplicity, allocate at high address
        addr = 0x70000000;  // Fixed address for now
    }

    // Round up to pages
    length = (length + PAGE_SIZE - 1) & ~(PAGE_SIZE - 1);

    for (uint64 va = addr; va < addr + length; va += PAGE_SIZE) {
        void *pa = kalloc_zero();
        if (!pa)
            return (uint64)-1;
        int perm = PTE_U;
        if (prot & 1) perm |= PTE_R;
        if (prot & 2) perm |= PTE_W;
        if (prot & 4) perm |= PTE_X;
        uvm_map(curr_proc->pgtbl, va, (uint64)pa, PAGE_SIZE, perm);
    }
    return addr;
}

static uint64 sys_munmap(struct trapframe *tf)
{
    (void)tf;
    return 0;
}

static uint64 sys_dup(struct trapframe *tf)
{
    int oldfd = tf->a0;
    return sys_dup3_impl(oldfd, -1);
}

