static int syscall_inited = 0;

void syscall_handle(struct trapframe *tf)
{
    if (!syscall_inited) {
        syscall_init_table();
        syscall_inited = 1;
    }

    uint64 nr = tf->a7;

    if (nr >= 512 || syscall_table[nr] == NULL) {
        uart_puts("syscall: unknown syscall #");
        if (nr >= 100) uart_putc('0' + nr / 100);
        if (nr >= 10) uart_putc('0' + (nr / 10) % 10);
        uart_putc('0' + nr % 10);
        uart_puts("\n");
        tf->a0 = -1;
        return;
    }

    uint64 ret = syscall_table[nr](tf);
    tf->a0 = ret;
}

