    uint64 p_paddr;
    uint64 p_filesz;
    uint64 p_memsz;
    uint64 p_align;
};

#define PT_LOAD 1
#define PF_R 4
#define PF_W 2
#define PF_X 1

#define EM_RISCV 243

struct proc;

int  elf_load(struct proc *p, const char *data, int size, uint64 *entry_out);
