// Load an ELF binary into the process's address space
// Returns 0 on success, -1 on error
// On success, *entry_out is set to the program entry point
int elf_load(struct proc *p, const char *data, int size, uint64 *entry_out)
{
    if (size < (int)sizeof(struct elf64_hdr))
        return -1;

    struct elf64_hdr *eh = (struct elf64_hdr *)data;

    // Check ELF magic
    if (eh->e_ident[0] != 0x7f || eh->e_ident[1] != 'E' ||
        eh->e_ident[2] != 'L' || eh->e_ident[3] != 'F')
        return -1;

    // 64-bit, little-endian, RISC-V
    if (eh->e_ident[4] != 2)   // ELFCLASS64
        return -1;
    if (eh->e_machine != EM_RISCV)
        return -1;

    *entry_out = eh->e_entry;

    uart_puts("ELF: entry=0x");
    for (int i = 28; i >= 0; i -= 4) {
        int nib = ((uint64)*entry_out >> i) & 0xf;
        uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
    }
    uart_puts(", phnum=");
    int phnum = eh->e_phnum;
    uart_putc('0' + phnum / 10);
    uart_putc('0' + phnum % 10);
    uart_puts("\n");

    // Load program headers
    struct elf64_phdr *ph = (struct elf64_phdr *)(data + eh->e_phoff);

    for (int i = 0; i < eh->e_phnum; i++, ph = (struct elf64_phdr *)((char *)ph + eh->e_phentsize)) {
        if (ph->p_type != PT_LOAD)
            continue;

        if (ph->p_filesz > ph->p_memsz)
            return -1;

        uint64 va_start = ph->p_vaddr & ~(PAGE_SIZE - 1);
        uint64 va_end = (ph->p_vaddr + ph->p_memsz + PAGE_SIZE - 1) & ~(PAGE_SIZE - 1);
        uint64 file_off = ph->p_vaddr & (PAGE_SIZE - 1);

        uart_puts("  LOAD: vaddr=0x");
        for (int j = 28; j >= 0; j -= 4) {
            int nib = (ph->p_vaddr >> j) & 0xf;
            uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
        }
        uart_puts(", memsz=0x");
        for (int j = 28; j >= 0; j -= 4) {
            int nib = (ph->p_memsz >> j) & 0xf;
            uart_putc(nib < 10 ? '0' + nib : 'a' + nib - 10);
        }
        uart_puts("\n");

        for (uint64 va = va_start; va < va_end; va += PAGE_SIZE) {
            void *pa = kalloc_zero();
            if (!pa) {
                uart_puts("ELF: out of memory!\n");
                return -1;
            }

            // Copy data from file into this page
            // Segment VA range: [p_vaddr, p_vaddr+p_filesz)
            // Page VA range:    [va, va+PAGE_SIZE)
            uint64 seg_start = va > ph->p_vaddr ? va : ph->p_vaddr;
            uint64 seg_end   = (va + PAGE_SIZE < ph->p_vaddr + ph->p_filesz)
                               ? (va + PAGE_SIZE) : (ph->p_vaddr + ph->p_filesz);

            if (seg_start < seg_end) {
                uint64 file_off = ph->p_offset + seg_start - ph->p_vaddr;
                uint64 page_off = seg_start - va;
                uint64 ncopy = seg_end - seg_start;
                for (uint64 j = 0; j < ncopy; j++) {
                    ((char *)pa)[page_off + j] = data[file_off + j];
                }
            }

            int perm = PTE_U;
            if (ph->p_flags & PF_R) perm |= PTE_R;
            if (ph->p_flags & PF_W) perm |= PTE_W;
            if (ph->p_flags & PF_X) perm |= PTE_X;

            uvm_map(p->pgtbl, va, (uint64)pa, PAGE_SIZE, perm);
        }
    }

    return 0;
}

