void virtio_init(void)
{
    uint64 addrs[] = {0x10001000, 0x10002000, 0x10003000, 0x10004000,
                      0x10005000, 0x10006000, 0x10007000, 0x10008000};

    for (int i = 0; i < 8; i++) {
        blk_base = (volatile uint32 *)addrs[i];

        if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 ||
            *R(VIRTIO_MMIO_VERSION) != 2 ||
            *R(VIRTIO_MMIO_DEVICE_ID) != 2 ||
            *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) {
            continue;
        }

        uart_puts("virtio: found disk at ");
        uint64 a = addrs[i];
        for (int j = 28; j >= 0; j -= 4)
            uart_putc("0123456789abcdef"[(a >> j) & 0xf]);
        uart_puts("\n");

        // Reset
        uint32 status = 0;
        *R(VIRTIO_MMIO_STATUS) = status;

        // ACKNOWLEDGE
        status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
        *R(VIRTIO_MMIO_STATUS) = status;

        // DRIVER
        status |= VIRTIO_CONFIG_S_DRIVER;
        *R(VIRTIO_MMIO_STATUS) = status;

        // Negotiate features
        uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
        features &= ~(1ULL << VIRTIO_BLK_F_RO);
        features &= ~(1ULL << VIRTIO_BLK_F_SCSI);
        features &= ~(1ULL << VIRTIO_BLK_F_CONFIG_WCE);
        features &= ~(1ULL << VIRTIO_BLK_F_MQ);
        features &= ~(1ULL << VIRTIO_F_ANY_LAYOUT);
        features &= ~(1ULL << VIRTIO_RING_F_EVENT_IDX);
        features &= ~(1ULL << VIRTIO_RING_F_INDIRECT_DESC);
        *R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

        // FEATURES_OK
        status |= VIRTIO_CONFIG_S_FEATURES_OK;
        *R(VIRTIO_MMIO_STATUS) = status;

        status = *R(VIRTIO_MMIO_STATUS);
        if (!(status & VIRTIO_CONFIG_S_FEATURES_OK)) {
            uart_puts("virtio: FEATURES_OK failed\n");
            continue;
        }

        // Init queue 0
        *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
        if (*R(VIRTIO_MMIO_QUEUE_READY)) {
            uart_puts("virtio: queue already ready!\n");
            continue;
        }

        uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
        if (max < NUM) {
            uart_puts("virtio: queue too small\n");
            continue;
        }

        desc  = (void *)kalloc_zero();
        avail = (void *)kalloc_zero();
        used  = (void *)kalloc_zero();
        if (!desc || !avail || !used) {
            uart_puts("virtio: OOM\n"); return;
        }

        *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;

        // Write physical addresses
        *R(VIRTIO_MMIO_QUEUE_DESC_LOW)   = (uint64)desc;
        *R(VIRTIO_MMIO_QUEUE_DESC_HIGH)  = (uint64)desc >> 32;
        *R(VIRTIO_MMIO_DRIVER_DESC_LOW)  = (uint64)avail;
        *R(VIRTIO_MMIO_DRIVER_DESC_HIGH) = (uint64)avail >> 32;
        *R(VIRTIO_MMIO_DEVICE_DESC_LOW)  = (uint64)used;
        *R(VIRTIO_MMIO_DEVICE_DESC_HIGH) = (uint64)used >> 32;

        *R(VIRTIO_MMIO_QUEUE_READY) = 1;

        for (int j = 0; j < NUM; j++) free_desc[j] = 1;
        used_idx = 0;

        status |= VIRTIO_CONFIG_S_DRIVER_OK;
        *R(VIRTIO_MMIO_STATUS) = status;

        // Print device info
        uint64 feat = *R(VIRTIO_MMIO_DEVICE_FEATURES);
        uint32 qmax = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
        uart_puts("virtio: features=0x");
        for (int j = 60; j >= 0; j -= 4) uart_putc("0123456789abcdef"[(feat >> j) & 0xf]);
        uart_puts(" qmax=");
        uart_putc('0' + qmax / 100);
        uart_putc('0' + (qmax / 10) % 10);
        uart_putc('0' + qmax % 10);
        uart_puts("\nvirtio: disk ready\n");
        return;
    }
    uart_puts("virtio: no disk found\n");
}

