    uint32 s_first_data_block, s_log_block_size, s_log_cluster_size;
    uint32 s_blocks_per_group, s_clusters_per_group, s_inodes_per_group;
    uint32 s_mtime, s_wtime;
    uint16 s_mnt_count, s_max_mnt_count, s_magic, s_state;
    uint16 s_errors, s_minor_rev_level;
    uint32 s_lastcheck, s_checkinterval, s_creator_os, s_rev_level;
    uint16 s_def_resuid, s_def_resgid;
    uint32 s_first_ino;
    uint16 s_inode_size, s_block_group_nr;
} __attribute__((packed));

struct ext4_bgd {
    uint32 bg_block_bitmap_lo, bg_inode_bitmap_lo, bg_inode_table_lo;
    uint16 bg_free_blocks_count_lo, bg_free_inodes_count_lo;
    uint16 bg_used_dirs_count_lo, bg_flags;
} __attribute__((packed));

struct ext4_inode {
    uint16 i_mode, i_uid;
    uint32 i_size_lo, i_atime, i_ctime, i_mtime, i_dtime;
    uint16 i_gid, i_links_count;
    uint32 i_blocks_lo, i_flags, i_osd1;
    uint32 i_block[15];
    uint32 i_generation, i_file_acl_lo, i_size_high;
} __attribute__((packed));

struct ext4_extent_header {
    uint16 eh_magic, eh_entries, eh_max, eh_depth;
    uint32 eh_generation;
} __attribute__((packed));

struct ext4_extent {
    uint32 ee_block;
    uint16 ee_len, ee_start_hi;
    uint32 ee_start_lo;
} __attribute__((packed));

struct ext4_dir_entry {
    uint32 inode;
    uint16 rec_len;
    uint8  name_len, file_type;
    char   name[];
} __attribute__((packed));

static uint32 block_size, inodes_per_group, blocks_per_group;
static uint32 inode_size;
static uint64 bgdt_block;
static int initialized;
static uint8 dma_buf[4096] __attribute__((aligned(16)));

static int read_block(uint64 blk, void *buf)
{
    uint64 sec = blk * (block_size / 512);
    int n = block_size / 512;
    return virtio_read(sec, buf, n) == n ? 0 : -1;
}

static int read_inode(uint32 nr, struct ext4_inode *ino)
{
    uint32 grp = (nr - 1) / inodes_per_group;
    uint32 idx = (nr - 1) % inodes_per_group;

    uint64 bgd_sec = (bgdt_block * block_size) / 512 + (grp * 32) / 512;
    if (virtio_read(bgd_sec, dma_buf, 1) != 1) return -1;

    struct ext4_bgd *bgd = (struct ext4_bgd *)(dma_buf + (grp * 32) % 512);
    uint64 off = (uint64)bgd->bg_inode_table_lo * block_size + idx * inode_size;
    if (virtio_read(off / 512, dma_buf, 1) != 1) return -1;

    int bo = off % 512;
    for (uint32 i = 0; i < sizeof(*ino) && i < inode_size; i++)
        ((uint8*)ino)[i] = dma_buf[bo + i];
    return 0;
}

static int read_extent(struct ext4_inode *ino, char *buf, int maxsz)
{
    struct ext4_extent_header *eh = (struct ext4_extent_header *)ino->i_block;
    if (eh->eh_magic != 0xF30A || eh->eh_depth != 0) return -1;

    int fsz = ino->i_size_lo, done = 0;
    struct ext4_extent *ext = (struct ext4_extent *)((char*)eh + sizeof(*eh));

    for (int e = 0; e < eh->eh_entries && done < fsz && done < maxsz; e++) {
        uint64 start = ((uint64)ext[e].ee_start_hi << 32) | ext[e].ee_start_lo;
        for (uint32 b = 0; b < ext[e].ee_len && done < fsz && done < maxsz; b++) {
            if (read_block(start + b, dma_buf) < 0) return done > 0 ? done : -1;
            int n = fsz - done;
            if (n > maxsz - done) n = maxsz - done;
            if (n > (int)block_size) n = block_size;
            for (int j = 0; j < n; j++) buf[done + j] = dma_buf[j];
            done += n;
        }
    }
    return done;
}

int ext4_init(void)
{
    // Read superblock to verify disk
    static uint8 sb[4096] __attribute__((aligned(4096)));
    if (virtio_read(2, sb, 1) != 1) return -1;

    struct ext4_superblock *s = (struct ext4_superblock *)sb;
    if (s->s_magic != 0xEF53) { uart_puts("ext4: bad magic\n"); return -1; }

    block_size = 1024 << s->s_log_block_size;
    inodes_per_group = s->s_inodes_per_group;
    blocks_per_group = s->s_blocks_per_group;
    inode_size = s->s_inode_size ? s->s_inode_size : 128;
    bgdt_block = s->s_first_data_block + 1;
    initialized = 1;

    uart_puts("ext4: bs=");
    uart_putc('0' + block_size / 1024);
    uart_puts("K\n");
    return 0;
}

int ext4_open(const char *path, char **data, int *size)
{
    if (!initialized) return -1;

    struct ext4_inode root;
    if (read_inode(2, &root) != 0) return -1;

    static uint8 dirbuf[4096] __attribute__((aligned(16)));
    int ds = root.i_size_lo;
    if (ds > 4096) ds = 4096;
    if (read_extent(&root, (char*)dirbuf, ds) < 0) return -1;

    for (int off = 0; off < ds; ) {
        struct ext4_dir_entry *de = (struct ext4_dir_entry *)(dirbuf + off);
        if (de->rec_len == 0 || off + de->rec_len > ds) break;

        if (de->inode != 0) {
            const char *p = path;
            if (*p == '/') p++;  // skip leading slash
            int match = 1;
            for (int i = 0; i < de->name_len; i++)
                if (de->name[i] != *p++) { match = 0; break; }
            if (match && *p == 0) {
                struct ext4_inode fio;
                if (read_inode(de->inode, &fio) != 0) return -1;
                char *fb = (char *)kalloc_page();
                if (!fb) return -1;
                int n = read_extent(&fio, fb, fio.i_size_lo);
                if (n < 0) return -1;
                *data = fb; *size = n;
                return 0;
            }
        }
        off += de->rec_len;
    }
    return -1;
}

void ext4_list_root(void)
{
    if (!initialized) return;

    struct ext4_inode root;
    if (read_inode(2, &root) != 0) return;

    static uint8 dirbuf[4096] __attribute__((aligned(16)));
    int ds = root.i_size_lo;
    if (ds > 4096) ds = 4096;
    if (read_extent(&root, (char*)dirbuf, ds) < 0) return;

    for (int off = 0; off < ds; ) {
        struct ext4_dir_entry *de = (struct ext4_dir_entry *)(dirbuf + off);
        if (de->rec_len == 0 || off + de->rec_len > ds) break;
        if (de->inode != 0) {
            for (int i = 0; i < de->name_len; i++) uart_putc(de->name[i]);
            uart_puts("\n");
        }
        off += de->rec_len;
    }
}

// Scan root directory for *_testcode.sh files, return test group names
int ext4_scan_testcode(char names[][64], int max_names)
{
    if (!initialized) return 0;

    struct ext4_inode root;
    if (read_inode(2, &root) != 0) return 0;

    static uint8 dirbuf[4096] __attribute__((aligned(16)));
    int ds = root.i_size_lo;
    if (ds > 4096) ds = 4096;
    if (read_extent(&root, (char*)dirbuf, ds) < 0) return 0;

    int count = 0;
    for (int off = 0; off < ds && count < max_names; ) {
        struct ext4_dir_entry *de = (struct ext4_dir_entry *)(dirbuf + off);
        if (de->rec_len == 0 || off + de->rec_len > ds) break;

        if (de->inode != 0 && de->name_len > 12) {
            // Check if filename ends with "_testcode.sh"
            char *suffix = "_testcode.sh";
            int slen = 12;
            int start = de->name_len - slen;
            if (start > 0) {
                int match = 1;
                for (int i = 0; i < slen; i++)
                    if (de->name[start + i] != suffix[i]) { match = 0; break; }
                if (match) {
                    // Extract group name (everything before "_testcode.sh")
                    int nlen = start;
                    if (nlen > 63) nlen = 63;
                    for (int i = 0; i < nlen; i++)
                        names[count][i] = de->name[i];
                    names[count][nlen] = 0;
                    count++;
                }
            }
        }
        off += de->rec_len;
    }
    return count;
}

