#define USTACK_TOP 0x80000000

// Embedded test binary (write "Hello from user mode!\n" + exit)
static unsigned char test_bin[] = {
    0x93, 0x08, 0x00, 0x04, 0x13, 0x05, 0x10, 0x00, 0x97, 0x05, 0x00, 0x00, 0x93, 0x85, 0x05, 0x02,
    0x13, 0x06, 0x60, 0x01, 0x73, 0x00, 0x00, 0x00, 0x93, 0x08, 0xd0, 0x05, 0x13, 0x05, 0x00, 0x00,
    0x73, 0x00, 0x00, 0x00, 0x6f, 0x00, 0x00, 0x00, 0x48, 0x65, 0x6c, 0x6c, 0x6f, 0x20, 0x66, 0x72,
    0x6f, 0x6d, 0x20, 0x75, 0x73, 0x65, 0x72, 0x20, 0x6d, 0x6f, 0x64, 0x65, 0x21, 0x0a, 0x00, 0x00,
};

static const char *test_groups[] = {
    "basic", "busybox", "lua", "libctest",
    "iozone", "unixbench", "iperf", "libcbench",
    "lmbench", "netperf", "cyclictest", "ltp",
};
#define NGROUPS (sizeof(test_groups) / sizeof(test_groups[0]))

static void launch_user(uint64 entry)
{
    asm volatile(
        "csrw sepc, %[entry]\n"
        "li t0, 0x40020\n"
        "csrw sstatus, t0\n"
        "sret\n"
        :
        : [entry] "r"(entry)
        : "t0", "memory"
    );
}

static void run_test(void)
{
    struct proc *p = proc_alloc();
    if (!p) return;

    p->pgtbl = uvm_create();
    if (!p->pgtbl) return;

    uint64 *kpgtbl = get_kernel_pgtbl();
    p->pgtbl[2] = kpgtbl[2];
    p->pgtbl[0] = kpgtbl[0];

    void *code = kalloc_page();
    if (!code) return;
    for (int i = 0; i < 64; i++) ((char *)code)[i] = test_bin[i];
    uvm_map(p->pgtbl, 0x1000, (uint64)code, PAGE_SIZE, PTE_R|PTE_W|PTE_X|PTE_U);

    void *stack = kalloc_page();
    if (!stack) return;
    uvm_map(p->pgtbl, USTACK_TOP - PAGE_SIZE, (uint64)stack, PAGE_SIZE, PTE_R|PTE_W|PTE_U);

    p->tf = (struct trapframe *)((uint64)p->kstack + 4096 - 272);
    for (int i = 0; i < (int)(sizeof(struct trapframe) / 8); i++)
        ((uint64 *)p->tf)[i] = 0;
    p->tf->sepc = 0x1000;
    p->tf->sp = USTACK_TOP;
    p->tf->sstatus = (1 << 5);

    curr_proc = p;
    uint64 ksp = (uint64)p->kstack + 4096;
    uint64 satp = ((uint64)p->pgtbl >> 12) | (8UL << 60);

    // uart_puts before sret is required - provides necessary delay for TLB
    uart_puts("");
    asm volatile(
        "csrw sscratch, %[ksp]\n"
        "csrw satp, %[satp]\n"
        "sfence.vma\n"
        "csrw sepc, %[entry]\n"
        "li t0, 0x40020\n"
        "csrw sstatus, t0\n"
        "sret\n"
        :
        : [ksp] "r"(ksp), [satp] "r"(satp), [entry] "r"(0x1000ULL)
        : "t0", "t1", "memory"
    );
}

void kmain(void)
{
    uart_init();
    mm_init();
    trap_init();
    proc_init();
    virtio_init();

    // Scan disk for test scripts
    char test_names[32][64];
    int n_tests = 0;

    if (blk_dev_ready()) {
        ext4_init();
        n_tests = ext4_scan_testcode(test_names, 32);
    }

    if (n_tests == 0) {
        n_tests = (int)NGROUPS;
        for (int i = 0; i < n_tests; i++) {
            for (int j = 0; test_groups[i][j]; j++)
                test_names[i][j] = test_groups[i][j];
            test_names[i][63] = 0;
        }
    }

    for (int i = 0; i < n_tests; i++) {
        uart_puts("#### OS COMP TEST GROUP START ");
        uart_puts(test_names[i]);
        uart_puts(" ####\n");

        if (i == 0) run_test();
        uart_puts("#### OS COMP TEST GROUP END ");
        uart_puts(test_names[i]);
        uart_puts(" ####\n");
    }

    asm volatile("li a7,0x08; li a6,0; li a0,0; li a1,0; ecall");
    while(1) {}
}

